+ * Each handler parses query parameters into an AnalyticsQuery,
+ * delegates to AnalyticsService, and wraps the result in AnalyticsResponse.
+ *
+ * Implementation note: This project doesn't use Express/Fastify yet.
+ * These handlers are framework-agnostic functions that accept parsed
+ * params and return typed response objects. When a web framework is
+ * added, wrap these in framework-specific route registration.
+ */
+
+import type {
+  AnalyticsQuery,
+  AnalyticsResponse,
+  DashboardData,
+  MetricSummary,
+  MetricType,
+  TimeGranularity,
+  TimeSeriesPoint,
+  TopProductEntry,
+} from '../models/analytics.js';
+import type { AnalyticsService } from '../services/analytics.service.js';
+
+const VALID_METRIC_TYPES: MetricType[] = ['orders', 'revenue', 'users', 'average-order-value'];
+const VALID_GRANULARITIES: TimeGranularity[] = ['hour', 'day', 'week', 'month'];
+
+/**
+ * Parse and validate analytics query parameters.
+ * Applies defaults for missing values.
+ */
+export function parseAnalyticsQuery(params: Record<string, string | undefined>): AnalyticsQuery {
+  const now = new Date();
+  const thirtyDaysAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
+
+  const startDate = params['startDate'] ?? thirtyDaysAgo.toISOString();
+  const endDate = params['endDate'] ?? now.toISOString();
+
+  const granularity = params['granularity'] as TimeGranularity | undefined;
+  if (granularity && !VALID_GRANULARITIES.includes(granularity)) {
+    throw new Error(`Invalid granularity: ${granularity}. Must be one of: ${VALID_GRANULARITIES.join(', ')}`);
+  }
+
+  return {
+    startDate,
+    endDate,
+    granularity: granularity ?? 'day',
+  };
+}
+
+/**
+ * Validate that a metric type string is a valid MetricType.
+ */
+export function validateMetricType(type: string): MetricType {
+  if (!VALID_METRIC_TYPES.includes(type as MetricType)) {
+    throw new Error(`Invalid metric type: ${type}. Must be one of: ${VALID_METRIC_TYPES.join(', ')}`);
+  }
+  return type as MetricType;
