+  const data = await analyticsService.getTimeSeries(query);
+  return { data, query };
+}
+
+/**
+ * Handler: GET /api/analytics/top-products
+ *
+ * Returns top products ranked by revenue.
+ * Query params: startDate, endDate, granularity, limit
+ */
+export async function handleGetTopProducts(
+  analyticsService: AnalyticsService,
