/**
 * Analytics data models for the dashboard API.
 *
 * These interfaces define the shape of analytics data returned by the API.
 * They are composable: small types (TimeSeriesPoint, MetricSummary) combine
 * into larger response types (DashboardData).
 *
 * Design note: All date fields use ISO 8601 strings in API responses
 * (not Date objects) for JSON serialization consistency.
 */

/**
 * Supported metric types for the analytics dashboard.
 */
export type MetricType = 'orders' | 'revenue' | 'users' | 'average-order-value';

/**
 * Time granularity for time-series aggregation.
 */
export type TimeGranularity = 'hour' | 'day' | 'week' | 'month';

/**
 * A single point in a time series.
 */
export interface TimeSeriesPoint {
  /** ISO 8601 timestamp for the start of this bucket */
  timestamp: string;
  /** Aggregated value for this time bucket */
  value: number;
  /** Optional label (e.g., "Monday", "Week 12") */
  label?: string;
}

/**
 * Summary of a single metric with comparison to a previous period.
 */
export interface MetricSummary {
  /** Which metric this summarizes */
  type: MetricType;
  /** Human-readable label */
  label: string;
  /** Current period value */
  current: number;
  /** Previous period value (for comparison) */
  previous: number;
  /** Percentage change from previous to current */
  changePercent: number;
  /** Whether the change direction is positive for the business */
  trend: 'up' | 'down' | 'flat';
}

/**
 * A ranked product entry for "top products" analytics.
 */
export interface TopProductEntry {
  /** Product identifier */
  productId: string;
  /** Product name */
  name: string;
  /** Total quantity sold in the period */
  totalQuantity: number;
  /** Total revenue generated in the period */
  totalRevenue: number;
}

/**
 * A recent order summary for the dashboard feed.
 */
export interface RecentOrderSummary {
  /** Order ID */
  orderId: string;
  /** User who placed the order */
  userName: string;
  /** Order total */
  total: number;
  /** Current status */
  status: string;
  /** When the order was created (ISO 8601) */
  createdAt: string;
}

/**
 * Composite dashboard response combining all analytics data.
 */
export interface DashboardData {
  /** Key metric summaries (orders, revenue, users, AOV) */
  metrics: MetricSummary[];
  /** Time series for the primary chart */
  timeSeries: TimeSeriesPoint[];
  /** Top performing products */
  topProducts: TopProductEntry[];
  /** Recent order activity feed */
  recentOrders: RecentOrderSummary[];
  /** When this dashboard data was generated (ISO 8601) */
  generatedAt: string;
}

/**
 * Query parameters for analytics endpoints.
 * All analytics endpoints accept these for filtering.
 */
export interface AnalyticsQuery {
  /** Start of the date range (ISO 8601) */
  startDate: string;
  /** End of the date range (ISO 8601) */
  endDate: string;
  /** Time bucket granularity for time-series data */
  granularity: TimeGranularity;
}

/**
 * Standard analytics API response wrapper.
 * All analytics endpoints return this shape.
 */
export interface AnalyticsResponse<T> {
  /** The analytics data payload */
  data: T;
  /** The query parameters that produced this result */
  query: AnalyticsQuery;
}

/**
 * Analytics service — business logic for dashboard analytics.
 *
 * Depends on:
 * - OrderRepository (data layer) for order data
 * - UserRepository (data layer) for user data
 *
 * Architecture note: This service reads from existing repositories rather than
 * maintaining a separate analytics store. This keeps the data source consistent
 * and avoids sync complexity. If read performance becomes an issue, a future
 * iteration could introduce a materialized analytics store populated via events.
 *
 * Implementation guide for the next developer:
 * 1. Replace the placeholder returns with real aggregation logic.
 * 2. Each public method corresponds to one API endpoint.
 * 3. Use the AnalyticsQuery param to filter data by date range.
 * 4. The getDashboard() method should compose results from the other methods
 *    to avoid duplicating aggregation logic.
 */

import type {
  AnalyticsQuery,
  DashboardData,
  MetricSummary,
  MetricType,
  TimeSeriesPoint,
  TopProductEntry,
  RecentOrderSummary,
} from '../models/analytics.js';
import type { OrderRepository } from '../repositories/order.repository.js';
import type { UserRepository } from '../repositories/user.repository.js';
import { Logger } from '../utils/logger.js';

export class AnalyticsService {
  private logger = new Logger('AnalyticsService');

  constructor(
    private orderRepository: OrderRepository,
    private userRepository: UserRepository,
  ) {}

  /**
   * Get the full dashboard data combining all analytics.
   *
   * Implementation: Compose from getMetric(), getTimeSeries(),
   * getTopProducts(), and getRecentOrders(). This avoids duplicating
   * aggregation logic across methods.
   */
  async getDashboard(query: AnalyticsQuery): Promise<DashboardData> {
    this.logger.info('Generating dashboard data');

    const [orderMetric, revenueMetric, userMetric, aovMetric] =
      await Promise.all([
        this.getMetric('orders', query),
        this.getMetric('revenue', query),
        this.getMetric('users', query),
        this.getMetric('average-order-value', query),
      ]);

    const [timeSeries, topProducts, recentOrders] = await Promise.all([
      this.getTimeSeries(query),
      this.getTopProducts(query),
      this.getRecentOrders(query),
    ]);

    return {
      metrics: [orderMetric, revenueMetric, userMetric, aovMetric],
      timeSeries,
      topProducts,
      recentOrders,
      generatedAt: new Date().toISOString(),
    };
  }

  /**
   * Get a single metric summary with period-over-period comparison.
   *
   * Implementation guide:
   * - 'orders': Count orders in the date range vs. the equivalent previous period.
   * - 'revenue': Sum order totals in the date range vs. previous.
   * - 'users': Count new users created in the date range vs. previous.
   * - 'average-order-value': revenue / orders for each period.
   * - Calculate changePercent as ((current - previous) / previous) * 100.
   * - Determine trend: 'up' if positive, 'down' if negative, 'flat' if zero.
   */
  async getMetric(type: MetricType, query: AnalyticsQuery): Promise<MetricSummary> {
    this.logger.info(`Computing metric: ${type}`);

    // TODO: Replace with real aggregation from repositories
    // Use query.startDate/endDate to filter, compute previous period automatically
    const _orders = this.orderRepository.findAll();
    const _users = this.userRepository.findAll();

    const labels: Record<MetricType, string> = {
      'orders': 'Total Orders',
      'revenue': 'Total Revenue',
      'users': 'New Users',
      'average-order-value': 'Avg Order Value',
    };

    return {
      type,
      label: labels[type],
      current: 0,
      previous: 0,
      changePercent: 0,
      trend: 'flat',
    };
  }

  /**
   * Get time series data for charting.
   *
   * Implementation guide:
   * - Group orders by time bucket (based on query.granularity).
   * - Each TimeSeriesPoint.timestamp = start of the bucket (ISO 8601).
   * - Each TimeSeriesPoint.value = count of orders (or revenue) in that bucket.
   * - Fill in empty buckets with value: 0 for continuous charts.
   */
  async getTimeSeries(query: AnalyticsQuery): Promise<TimeSeriesPoint[]> {
    this.logger.info(`Computing time series (${query.granularity})`);

    // TODO: Replace with real time-bucketed aggregation
    const _orders = this.orderRepository.findAll();

    return [];
  }

  /**
   * Get top products ranked by revenue.
   *
   * Implementation guide:
   * - Flatten all OrderItems from orders in the date range.
   * - Group by productId, summing quantity and revenue.
   * - Sort by totalRevenue descending, return top 10.
   */
  async getTopProducts(query: AnalyticsQuery, limit: number = 10): Promise<TopProductEntry[]> {
    this.logger.info(`Computing top ${limit} products`);

    // TODO: Replace with real product aggregation
    const _orders = this.orderRepository.findAll();
    void query;

    return [];
  }

  /**
   * Get recent orders for the activity feed.
   *
   * Implementation guide:
   * - Fetch the N most recent orders (default 10).
   * - Join with user data to get userName.
   * - Filter by date range from query.
   * - Sort by createdAt descending.
   */
  async getRecentOrders(query: AnalyticsQuery, limit: number = 10): Promise<RecentOrderSummary[]> {
    this.logger.info(`Fetching ${limit} recent orders`);

    // TODO: Replace with real query + user join
    const _orders = this.orderRepository.findAll();
    const _users = this.userRepository.findAll();
    void query;

    return [];
  }
}

/**
 * Analytics route handlers for the dashboard API.
 *
 * Route structure:
 * - GET /api/analytics/dashboard      — Full dashboard composite data
 * - GET /api/analytics/metrics/:type   — Single metric with comparison
 * - GET /api/analytics/timeseries      — Time series for charting
 * - GET /api/analytics/top-products    — Top products by revenue
 *
 * These are stub handlers that return placeholder responses.
 * Each handler parses query parameters into an AnalyticsQuery,
 * delegates to AnalyticsService, and wraps the result in AnalyticsResponse.
 *
 * Implementation note: This project doesn't use Express/Fastify yet.
 * These handlers are framework-agnostic functions that accept parsed
 * params and return typed response objects. When a web framework is
 * added, wrap these in framework-specific route registration.
 */

import type {
  AnalyticsQuery,
  AnalyticsResponse,
  DashboardData,
  MetricSummary,
  MetricType,
  TimeGranularity,
  TimeSeriesPoint,
  TopProductEntry,
} from '../models/analytics.js';
import type { AnalyticsService } from '../services/analytics.service.js';

const VALID_METRIC_TYPES: MetricType[] = ['orders', 'revenue', 'users', 'average-order-value'];
const VALID_GRANULARITIES: TimeGranularity[] = ['hour', 'day', 'week', 'month'];

/**
 * Parse and validate analytics query parameters.
 * Applies defaults for missing values.
 */
export function parseAnalyticsQuery(params: Record<string, string | undefined>): AnalyticsQuery {
  const now = new Date();
  const thirtyDaysAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);

  const startDate = params['startDate'] ?? thirtyDaysAgo.toISOString();
  const endDate = params['endDate'] ?? now.toISOString();

  const granularity = params['granularity'] as TimeGranularity | undefined;
  if (granularity && !VALID_GRANULARITIES.includes(granularity)) {
    throw new Error(`Invalid granularity: ${granularity}. Must be one of: ${VALID_GRANULARITIES.join(', ')}`);
  }

  return {
    startDate,
    endDate,
    granularity: granularity ?? 'day',
  };
}

/**
 * Validate that a metric type string is a valid MetricType.
 */
export function validateMetricType(type: string): MetricType {
  if (!VALID_METRIC_TYPES.includes(type as MetricType)) {
    throw new Error(`Invalid metric type: ${type}. Must be one of: ${VALID_METRIC_TYPES.join(', ')}`);
  }
  return type as MetricType;
}

/**
 * Handler: GET /api/analytics/dashboard
 *
 * Returns the full composite dashboard data.
 * Query params: startDate, endDate, granularity
 */
export async function handleGetDashboard(
  analyticsService: AnalyticsService,
  params: Record<string, string | undefined>,
): Promise<AnalyticsResponse<DashboardData>> {
  const query = parseAnalyticsQuery(params);
  const data = await analyticsService.getDashboard(query);
  return { data, query };
}

/**
 * Handler: GET /api/analytics/metrics/:type
 *
 * Returns a single metric summary with period-over-period comparison.
 * Path param: type (orders | revenue | users | average-order-value)
 * Query params: startDate, endDate, granularity
 */
export async function handleGetMetric(
  analyticsService: AnalyticsService,
  metricType: string,
  params: Record<string, string | undefined>,
): Promise<AnalyticsResponse<MetricSummary>> {
  const type = validateMetricType(metricType);
  const query = parseAnalyticsQuery(params);
  const data = await analyticsService.getMetric(type, query);
  return { data, query };
}

/**
 * Handler: GET /api/analytics/timeseries
 *
 * Returns time series data points for charting.
 * Query params: startDate, endDate, granularity
 */
export async function handleGetTimeSeries(
  analyticsService: AnalyticsService,
  params: Record<string, string | undefined>,
): Promise<AnalyticsResponse<TimeSeriesPoint[]>> {
  const query = parseAnalyticsQuery(params);
  const data = await analyticsService.getTimeSeries(query);
  return { data, query };
}

/**
 * Handler: GET /api/analytics/top-products
 *
 * Returns top products ranked by revenue.
 * Query params: startDate, endDate, granularity, limit
 */
export async function handleGetTopProducts(
  analyticsService: AnalyticsService,
  params: Record<string, string | undefined>,
): Promise<AnalyticsResponse<TopProductEntry[]>> {
  const query = parseAnalyticsQuery(params);
  const limit = params['limit'] ? parseInt(params['limit'], 10) : 10;
  if (isNaN(limit) || limit < 1) {
    throw new Error('limit must be a positive integer');
  }
  const data = await analyticsService.getTopProducts(query, limit);
  return { data, query };
}

